 1â†’import { useEffect } from "react";
 2â†’import { useOrganization } from "../../contexts/OrganizationContext";
 3â†’import { authClient } from "../../lib/auth-client";
 4â†’import { ensureChatwootLoaded, syncChatwootUser } from "../../lib/chatwoot";
 5â†’
 6â†’export function ChatwootBootstrap() {
 7â†’	const { data: session } = authClient.useSession();
 8â†’	const { activeOrg } = useOrganization();
 9â†’
10â†’	useEffect(() => {
11â†’		void ensureChatwootLoaded().catch(() => {
12â†’			// Keep the dashboard usable even if Chatwoot is unavailable.
13â†’		});
14â†’	}, []);
15â†’
16â†’	useEffect(() => {
17â†’		if (!session?.user) {
18â†’			return;
19â†’		}
20â†’
21â†’		const identifier =
22â†’			("id" in session.user && typeof session.user.id === "string"
23â†’				? session.user.id
24â†’				: undefined) ??
25â†’			("email" in session.user && typeof session.user.email === "string"
26â†’				? session.user.email
27â†’				: undefined);
28â†’
29â†’		if (!identifier) {
30â†’			return;
31â†’		}
32â†’
33â†’		void syncChatwootUser({
34â†’			identifier,
35â†’			email:
36â†’				"email" in session.user && typeof session.user.email === "string"
37â†’					? session.user.email
38â†’					: undefined,
39â†’			name: session.user.name,
40â†’			avatarUrl: session.user.image,
41â†’			organizationName: activeOrg?.name,
42â†’		});
43â†’	}, [activeOrg?.name, session?.user]);
44â†’
45â†’	return null;
46â†’}
