  1â†’import { join } from "node:path";
  2â†’import { getLogger, withContext } from "@logtape/logtape";
  3â†’import { onError } from "@orpc/server";
  4â†’import { RPCHandler } from "@orpc/server/fetch";
  5â†’import { user as userTable } from "@rudel/sql-schema";
  6â†’import { eq } from "drizzle-orm";
  7â†’import type { Session as AuthSession } from "./auth.js";
  8â†’import { createAuth } from "./auth.js";
  9â†’import { db } from "./db.js";
 10â†’import { setupLogging } from "./logging.js";
 11â†’import { router } from "./router.js";
 12â†’
 13â†’await setupLogging();
 14â†’
 15â†’const logger = getLogger(["rudel", "api", "http"]);
 16â†’type AuthUser = AuthSession["user"];
 17â†’
 18â†’const socialProviders: Record<
 19â†’	string,
 20â†’	{ clientId: string; clientSecret: string }
 21â†’> = {};
 22â†’if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
 23â†’	socialProviders.google = {
 24â†’		clientId: process.env.GOOGLE_CLIENT_ID,
 25â†’		clientSecret: process.env.GOOGLE_CLIENT_SECRET,
 26â†’	};
 27â†’}
 28â†’if (process.env.GITHUB_CLIENT_ID && process.env.GITHUB_CLIENT_SECRET) {
 29â†’	socialProviders.github = {
 30â†’		clientId: process.env.GITHUB_CLIENT_ID,
 31â†’		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 32â†’	};
 33â†’}
 34â†’
 35â†’const appURL = process.env.APP_URL ?? "http://localhost:4010";
 36â†’const ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 37â†’const trustedOrigins = process.env.TRUSTED_ORIGINS
 38â†’	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 39â†’	: [ALLOWED_ORIGIN];
 40â†’
 41â†’const auth = createAuth(db, {
 42â†’	appURL,
 43â†’	secret: process.env.BETTER_AUTH_SECRET,
 44â†’	socialProviders,
 45â†’	trustedOrigins,
 46â†’	cliDeviceVerificationUrl:
 47â†’		process.env.CLI_DEVICE_VERIFICATION_URL ?? `${ALLOWED_ORIGIN}/device`,
 48â†’	slackWebhookUrl: process.env.SLACK_WEBHOOK_URL,
 49â†’});
 50â†’
 51â†’const rpcHandler = new RPCHandler(router, {
 52â†’	interceptors: [
 53â†’		onError((error) => {
 54â†’			logger.error("RPC unhandled exception: {error} {stack}", {
 55â†’				error: String(error),
 56â†’				stack: error instanceof Error ? error.stack : undefined,
 57â†’			});
 58â†’		}),
 59â†’	],
 60â†’});
 61â†’
 62â†’const STATIC_DIR = join(
 63â†’	import.meta.dir,
 64â†’	"..",
 65â†’	process.env.STATIC_DIR ?? "public",
 66â†’);
 67â†’
 68â†’function getPublicRuntimeConfig() {
 69â†’	return {
 70â†’		CHATWOOT_BASE_URL:
 71â†’			process.env.VITE_CHATWOOT_BASE_URL ?? process.env.CHATWOOT_BASE_URL ?? "",
 72â†’		CHATWOOT_WEBSITE_TOKEN:
 73â†’			process.env.VITE_CHATWOOT_WEBSITE_TOKEN ??
 74â†’			process.env.CHATWOOT_WEBSITE_TOKEN ??
 75â†’			"",
 76â†’		CHATWOOT_ENABLED:
 77â†’			process.env.VITE_CHATWOOT_ENABLED ?? process.env.CHATWOOT_ENABLED ?? "",
 78â†’	};
 79â†’}
 80â†’
 81â†’function corsHeaders(origin: string | null): Record<string, string> {
 82â†’	if (origin !== ALLOWED_ORIGIN) return {};
 83â†’	return {
 84â†’		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 85â†’		"Access-Control-Allow-Credentials": "true",
 86â†’		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 87â†’		"Access-Control-Allow-Headers": "Content-Type, Authorization, X-API-Key",
 88â†’	};
 89â†’}
 90â†’
 91â†’const port = process.env.PORT ?? 4010;
 92â†’const MAX_REQUEST_BODY_BYTES = Number(
 93â†’	process.env.MAX_REQUEST_BODY_BYTES ?? 500 * 1024 * 1024, // 500 MB
 94â†’);
 95â†’
 96â†’const server = Bun.serve({
 97â†’	port,
 98â†’	async fetch(request) {
 99â†’		const origin = request.headers.get("Origin");
100â†’		const cors = corsHeaders(origin);
101â†’
102â†’		if (request.method === "OPTIONS") {
103â†’			return new Response(null, { status: 204, headers: cors });
104â†’		}
105â†’
106â†’		const contentLength = request.headers.get("Content-Length");
107â†’		if (contentLength && Number(contentLength) > MAX_REQUEST_BODY_BYTES) {
108â†’			return new Response(
109â†’				JSON.stringify({
110â†’					error: `Request body too large. Maximum size is ${Math.round(MAX_REQUEST_BODY_BYTES / (1024 * 1024))} MB.`,
111â†’				}),
112â†’				{
113â†’					status: 413,
114â†’					headers: { ...cors, "Content-Type": "application/json" },
115â†’				},
116â†’			);
117â†’		}
118â†’
119â†’		const url = new URL(request.url);
120â†’
121â†’		// Health check for Fly.io (must be GET-accessible)
122â†’		if (url.pathname === "/health") {
123â†’			return Response.json({ status: "ok", timestamp: Date.now() });
124â†’		}
125â†’
126â†’		const requestId = crypto.randomUUID();
127â†’		const start = performance.now();
128â†’
129â†’		return withContext(
130â†’			{ requestId, method: request.method, path: url.pathname },
131â†’			async () => {
132â†’				const response = await handleRequest(request, url, cors);
133â†’				const duration = Math.round(performance.now() - start);
134â†’				logger.info("{method} {path} {status} {duration}ms", {
135â†’					method: request.method,
136â†’					path: url.pathname,
137â†’					status: response.status,
138â†’					duration,
139â†’				});
140â†’				return response;
141â†’			},
142â†’		);
143â†’	},
144â†’});
145â†’
146â†’async function handleRequest(
147â†’	request: Request,
148â†’	url: URL,
149â†’	cors: Record<string, string>,
150â†’): Promise<Response> {
151â†’	// Defense in depth: block Better Auth's built-in org deletion route.
152â†’	// Rudel has its own guarded deletion path via the RPC router.
153â†’	if (url.pathname === "/api/auth/organization/delete") {
154â†’		return new Response("Not Found", { status: 404, headers: cors });
155â†’	}
156â†’	if (url.pathname.startsWith("/api/auth")) {
157â†’		const response = await auth.handler(request);
158â†’		for (const [key, value] of Object.entries(cors)) {
159â†’			response.headers.set(key, value);
160â†’		}
161â†’		return response;
162â†’	}
163â†’
164â†’	if (url.pathname === "/api/runtime-config") {
165â†’		return Response.json(getPublicRuntimeConfig(), {
166â†’			headers: {
167â†’				...cors,
168â†’				"Cache-Control": "no-store",
169â†’			},
170â†’		});
171â†’	}
172â†’
173â†’	const { matched, response } = await rpcHandler.handle(request, {
174â†’		prefix: "/rpc",
175â†’		context: await getContext(request),
176â†’	});
177â†’
178â†’	if (matched) {
179â†’		if (response.status >= 500) {
180â†’			const body = await response.clone().text();
181â†’			logger.error("RPC error on {path}: {status} {body}", {
182â†’				path: url.pathname,
183â†’				status: response.status,
184â†’				body,
185â†’			});
186â†’		}
187â†’		for (const [key, value] of Object.entries(cors)) {
188â†’			response.headers.set(key, value);
189â†’		}
190â†’		return response;
191â†’	}
192â†’
193â†’	// Static file serving (production: frontend assets)
194â†’	const filePath = join(STATIC_DIR, url.pathname);
195â†’	const file = Bun.file(filePath);
196â†’	if (await file.exists()) {
197â†’		return new Response(file);
198â†’	}
199â†’
200â†’	// SPA fallback: serve index.html for non-API routes
201â†’	const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
202â†’	if (await indexFile.exists()) {
203â†’		return new Response(indexFile);
204â†’	}
205â†’
206â†’	// Dev mode: redirect to frontend dev server for non-API routes
207â†’	// (e.g., after OAuth callback redirects to APP_URL which has no SPA)
208â†’	if (ALLOWED_ORIGIN !== appURL) {
209â†’		return Response.redirect(
210â†’			`${ALLOWED_ORIGIN}${url.pathname}${url.search}`,
211â†’			302,
212â†’		);
213â†’	}
214â†’
215â†’	return new Response("Not found", { status: 404, headers: cors });
216â†’}
