218â†’async function getContext(request: Request) {
219â†’	const session = await auth.api.getSession({
220â†’		headers: request.headers,
221â†’	});
222â†’
223â†’	let apiKeyId: string | null = null;
224â†’	const apiKey =
225â†’		request.headers.get("x-api-key") ??
226â†’		request.headers.get("X-API-Key") ??
227â†’		null;
228â†’
229â†’	let apiKeyUser: AuthUser | null = null;
230â†’	if (apiKey) {
231â†’		try {
232â†’			const verification = await auth.api.verifyApiKey({
233â†’				body: {
234â†’					key: apiKey,
235â†’					permissions: { ingest: ["write"] },
236â†’				},
237â†’			});
238â†’
239â†’			if (verification.valid && verification.key) {
240â†’				const [foundUser] = await db
241â†’					.select({
242â†’						id: userTable.id,
243â†’						name: userTable.name,
244â†’						email: userTable.email,
245â†’						emailVerified: userTable.emailVerified,
246â†’						image: userTable.image,
247â†’						createdAt: userTable.createdAt,
248â†’						updatedAt: userTable.updatedAt,
249â†’					})
250â†’					.from(userTable)
251â†’					.where(eq(userTable.id, verification.key.referenceId))
252â†’					.limit(1);
253â†’
254â†’				if (foundUser) {
255â†’					apiKeyUser = foundUser as AuthUser;
256â†’					apiKeyId = verification.key.id;
257â†’				}
258â†’			}
259â†’		} catch {
260â†’			// Invalid API key is treated as unauthenticated for key-based auth.
261â†’		}
262â†’	}
263â†’
264â†’	return {
265â†’		user: session?.user ?? apiKeyUser ?? null,
266â†’		session: session?.session ?? null,
267â†’		apiKeyId,
268â†’	};
269â†’}
270â†’
271â†’logger.info("API server listening on http://localhost:{port}", {
272â†’	port: server.port,
273â†’});
