12â†’async function getLatestGitHubVersion() {
13â†’	const response = await fetch(
14â†’		"https://api.github.com/repos/obsessiondb/rudel/releases/latest",
15â†’		{
16â†’			headers: {
17â†’				Accept: "application/vnd.github+json",
18â†’				"User-Agent": "rudel-web-build",
19â†’			},
20â†’		},
21â†’	);
22â†’
23â†’	if (!response.ok) {
24â†’		throw new Error(`GitHub returned ${response.status}`);
25â†’	}
26â†’
27â†’	const data = (await response.json()) as { tag_name?: string };
28â†’
29â†’	if (!data.tag_name) {
30â†’		throw new Error("GitHub release response did not include a tag");
31â†’	}
32â†’
33â†’	return data.tag_name.replace(/^rudel@/, "");
34â†’}
35â†’
36â†’function getLatestLocalTagVersion() {
37â†’	const output = execFileSync("git", ["tag", "--sort=-version:refname"], {
38â†’		cwd: __dirname,
39â†’		encoding: "utf-8",
40â†’	});
41â†’
42â†’	const tag = output
43â†’		.split("\n")
44â†’		.map((line) => line.trim())
45â†’		.find(Boolean);
46â†’
47â†’	if (!tag) {
48â†’		throw new Error("No git tags found");
49â†’	}
50â†’
51â†’	return tag.replace(/^rudel@/, "");
52â†’}
53â†’
54â†’async function resolveAppVersion() {
55â†’	try {
56â†’		return await getLatestGitHubVersion();
57â†’	} catch {
58â†’		try {
59â†’			return getLatestLocalTagVersion();
60â†’		} catch {
61â†’			return version;
62â†’		}
63â†’	}
64â†’}
65â†’
66â†’export default defineConfig(async () => {
67â†’	const appVersion = await resolveAppVersion();
68â†’
69â†’	return {
